/**
 * Input Sanitization Security Test Script
 * Tests all Edge Functions against various attack vectors
 */

const SUPABASE_URL = process.env.VITE_SUPABASE_URL || 'https://tjxnjhjkxldhupitkvqk.supabase.co';
const TURNSTILE_SITE_KEY = process.env.VITE_TURNSTILE_SITE_KEY || '0x4AAAAAAAJ42TdVf9DgmUVE';

// Color codes for terminal output
const colors = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m'
};

// Mock Turnstile token (in production, this would be generated by Turnstile)
const MOCK_TURNSTILE_TOKEN = 'test_token_for_security_testing_' + Date.now();

// Test results tracking
const results = {
  total: 0,
  passed: 0,
  failed: 0,
  skipped: 0
};

/**
 * Log test result
 */
function logResult(testName, status, message = '') {
  results.total++;
  
  if (status === 'PASS') {
    results.passed++;
    console.log(`${colors.green}✓ PASS${colors.reset} ${testName}${message ? ': ' + message : ''}`);
  } else if (status === 'FAIL') {
    results.failed++;
    console.log(`${colors.red}✗ FAIL${colors.reset} ${testName}${message ? ': ' + message : ''}`);
  } else if (status === 'SKIP') {
    results.skipped++;
    console.log(`${colors.yellow}⊘ SKIP${colors.reset} ${testName}${message ? ': ' + message : ''}`);
  }
}

/**
 * Test helper function
 */
async function testEndpoint(endpoint, payload, expectation) {
  try {
    const response = await fetch(`${SUPABASE_URL}/functions/v1/${endpoint}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Origin': 'http://localhost:5173'
      },
      body: JSON.stringify(payload)
    });

    const result = await response.json();
    
    // Log detailed response for debugging
    console.log(`  [DEBUG] Status: ${response.status}, Success: ${result.success}, Error: ${result.error?.substring(0, 100)}`);
    
    return {
      status: response.status,
      data: result,
      ok: response.ok
    };
  } catch (error) {
    return {
      status: 0,
      error: error.message,
      ok: false
    };
  }
}

/**
 * XSS Attack Tests
 */
async function testXSSAttacks() {
  console.log(`\n${colors.cyan}=== Testing XSS Attack Prevention ===${colors.reset}\n`);

  const xssPayloads = [
    '<script>alert("XSS")</script>',
    '<img src=x onerror=alert("XSS")>',
    '<svg onload=alert("XSS")>',
    'javascript:alert("XSS")',
    '<iframe src="javascript:alert(\'XSS\')"></iframe>'
  ];

  // Test Conference Registration
  for (const xssPayload of xssPayloads) {
    const payload = {
      firstName: xssPayload,
      lastName: 'TestUser',
      email: 'test@example.com',
      phone: '6155551234',
      schoolDistrict: 'Test District',
      streetAddress: '123 Main St',
      city: 'Nashville',
      state: 'TN',
      zipCode: '37201',
      totalAttendees: 1,
      totalAmount: 100,
      conferenceId: 1,
      paymentMethod: 'po',
      poNumber: 'PO12345',
      turnstileToken: MOCK_TURNSTILE_TOKEN
    };

    const result = await testEndpoint('submit-conference-registration', payload);
    
    // Should reject XSS payload
    if (!result.ok && result.data?.error) {
      logResult(`XSS in firstName: "${xssPayload.substring(0, 30)}..."`, 'PASS', 'Rejected malicious input');
    } else {
      logResult(`XSS in firstName: "${xssPayload.substring(0, 30)}..."`, 'FAIL', 'Malicious input was accepted');
    }
  }

  // Test Contact Message
  const contactXSSPayload = {
    name: 'Test User',
    email: 'test@example.com',
    message: '<script>alert("XSS in message")</script><h1>HTML injection</h1>',
    turnstileToken: MOCK_TURNSTILE_TOKEN
  };

  const contactResult = await testEndpoint('submit-contact-message', contactXSSPayload);
  
  if (!contactResult.ok && contactResult.data?.error) {
    logResult('XSS in contact message', 'PASS', 'Rejected script tags in message');
  } else {
    logResult('XSS in contact message', 'FAIL', 'Script tags in message were accepted');
  }
}

