/**
 * SQL Injection Tests
 */
async function testSQLInjection() {
  console.log(`\n${colors.cyan}=== Testing SQL Injection Prevention ===${colors.reset}\n`);

  const sqlPayloads = [
    "'; DROP TABLE users; --",
    "1' OR '1'='1",
    "admin'--",
    "' UNION SELECT * FROM users--"
  ];

  for (const sqlPayload of sqlPayloads) {
    const payload = {
      firstName: 'John',
      lastName: sqlPayload,
      email: 'test@example.com',
      phone: '6155551234',
      schoolDistrict: 'Test District',
      streetAddress: '123 Main St',
      city: 'Nashville',
      state: 'TN',
      zipCode: '37201',
      totalAttendees: 1,
      totalAmount: 100,
      conferenceId: 1,
      paymentMethod: 'po',
      poNumber: 'PO12345',
      turnstileToken: MOCK_TURNSTILE_TOKEN
    };

    const result = await testEndpoint('submit-conference-registration', payload);
    
    // Note: SQL injection is primarily prevented by parameterized queries,
    // but sanitization adds an extra layer
    if (!result.ok || result.data?.success === true) {
      logResult(`SQL injection in lastName: "${sqlPayload.substring(0, 30)}..."`, 'PASS', 'Query handled safely');
    } else {
      logResult(`SQL injection in lastName: "${sqlPayload.substring(0, 30)}..."`, 'FAIL', 'Unexpected behavior');
    }
  }
}

