/**
 * Print summary
 */
function printSummary() {
  console.log(`\n${colors.magenta}${'='.repeat(50)}${colors.reset}`);
  console.log(`${colors.magenta}Test Summary${colors.reset}`);
  console.log(`${colors.magenta}${'='.repeat(50)}${colors.reset}`);
  console.log(`Total Tests:  ${results.total}`);
  console.log(`${colors.green}Passed:       ${results.passed}${colors.reset}`);
  console.log(`${colors.red}Failed:       ${results.failed}${colors.reset}`);
  console.log(`${colors.yellow}Skipped:      ${results.skipped}${colors.reset}`);
  
  const successRate = results.total > 0 ? ((results.passed / results.total) * 100).toFixed(1) : 0;
  console.log(`\nSuccess Rate: ${successRate}%`);
  
  if (results.failed === 0) {
    console.log(`\n${colors.green}✓ All security tests passed!${colors.reset}`);
  } else {
    console.log(`\n${colors.red}✗ Some security tests failed. Please review the issues above.${colors.reset}`);
  }
  console.log(`${colors.magenta}${'='.repeat(50)}${colors.reset}\n`);
}

/**
 * Main test runner
 */
async function runTests() {
  console.log(`${colors.cyan}${'='.repeat(50)}${colors.reset}`);
  console.log(`${colors.cyan}Input Sanitization Security Test Suite${colors.reset}`);
  console.log(`${colors.cyan}Testing Supabase URL: ${SUPABASE_URL}${colors.reset}`);
  console.log(`${colors.cyan}${'='.repeat(50)}${colors.reset}`);
  
  console.log(`\n${colors.yellow}Note: Tests will fail Turnstile verification in production.${colors.reset}`);
  console.log(`${colors.yellow}We're testing that validation logic works before Turnstile check.${colors.reset}\n`);

  try {
    await testXSSAttacks();
    await testHTMLInjection();
    await testEventHandlerInjection();
    await testNullByteAttacks();
    await testOversizedInputs();
    await testSQLInjection();
    await testEmailValidation();
    await testPhoneValidation();
    await testZipCodeValidation();
    
    printSummary();
  } catch (error) {
    console.error(`\n${colors.red}Test suite error:${colors.reset}`, error);
    process.exit(1);
  }
}

// Run tests
runTests();
